const body = $input.first().json.body ?? $input.first().json;

const {
  sequence_id,
  step_id,
  step_number,
  step_name,
  scheduled_date,
  duration_minutes,
  notes,
  insert_after,
  cascade_mode = 'none',
  cascade_days = 0,
  notify_patient = false,
} = body;

if (!sequence_id) throw new Error('sequence_id is required');
if (!step_name?.trim()) throw new Error('step_name is required');
if (!step_number || step_number < 1) throw new Error('step_number must be >= 1');

const isUpdate = !!step_id;
const doCascade = cascade_mode !== 'none' && cascade_days !== 0;

return [{
  json: {
    sequence_id,
    step_id: step_id || null,
    step_number,
    step_name: step_name.trim(),
    scheduled_date: scheduled_date || null,
    duration_minutes: duration_minutes || 60,
    notes: notes || null,
    insert_after: insert_after || null,
    cascade_mode,
    cascade_days: parseInt(cascade_days, 10) || 0,
    notify_patient,
    isUpdate,
    doCascade,
  }
}];

// For INSERT: first renumber steps >= insert_after+1 to make room
const { sequence_id, step_number, insert_after } = $input.first().json;

// If inserting at a specific position, push subsequent step_numbers up
const insertPosition = insert_after ? insert_after + 1 : step_number;

const renumberSQL = `
  UPDATE treatment_steps
  SET step_number = step_number + 1
  WHERE sequence_id = '${sequence_id}'
    AND step_number >= ${insertPosition}
`;

const insertSQL = `
  INSERT INTO treatment_steps (sequence_id, step_number, step_name, scheduled_date, duration_minutes, notes, status)
  VALUES (
    '${sequence_id}',
    ${insertPosition},
    '${$input.first().json.step_name.replace(/'/g, "''")}',
    ${ $input.first().json.scheduled_date ? `'${$input.first().json.scheduled_date}'` : 'NULL' },
    ${ $input.first().json.duration_minutes || 60 },
    ${ $input.first().json.notes ? `'${$input.first().json.notes.replace(/'/g, "''")}'` : 'NULL' },
    'pending'
  )
  RETURNING id, sequence_id, step_number, step_name, scheduled_date, duration_minutes, status, notes, appointment_id, completed_at
`;

return [{ json: { ...$input.first().json, renumberSQL, insertSQL, insertPosition } }];

// Build cascade SQL: shift dates of subsequent steps and linked appointments
const parse = $('Parse Input').first().json;
const { sequence_id, step_number, cascade_days, cascade_mode } = parse;

// Get the step_number of the just-saved step
const savedStepNumber = step_number;

// Shift subsequent treatment_steps dates
const stepCascadeSQL = `
  UPDATE treatment_steps
  SET scheduled_date = (scheduled_date::date + INTERVAL '${cascade_days} days')::date
  WHERE sequence_id = '${sequence_id}'
    AND step_number > ${savedStepNumber}
    AND scheduled_date IS NOT NULL
`;

// Shift linked appointment datetimes for subsequent steps
const apptCascadeSQL = `
  UPDATE appointments
  SET
    start_datetime = start_datetime + INTERVAL '${cascade_days} days',
    end_datetime   = end_datetime   + INTERVAL '${cascade_days} days'
  WHERE sequence_id = '${sequence_id}'
    AND step_position > ${savedStepNumber}
    AND status NOT IN ('cancelled', 'completed')
`;

return [{ json: { sequence_id, stepCascadeSQL, apptCascadeSQL } }];

// After cascade (or skip), fetch all steps for the sequence to return
const parse = $('Parse Input').first().json;
return [{ json: { sequence_id: parse.sequence_id } }];

const allRows = $input.all();
const steps = allRows.map(r => ({
  id: r.json.id,
  sequence_id: r.json.sequence_id,
  step_number: r.json.step_number,
  step_name: r.json.step_name,
  scheduled_date: r.json.scheduled_date || null,
  duration_minutes: r.json.duration_minutes,
  status: r.json.status,
  notes: r.json.notes || null,
  appointment_id: r.json.appointment_id || null,
  completed_at: r.json.completed_at || null,
}));
return [{ json: { success: true, affected_steps: steps } }];
